import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import axios from "axios";

const Navbar = () => {
  const [open, setOpen] = useState(false);
  const [categories, setCategories] = useState([]);
  const API_BASE = process.env.REACT_APP_API_URL || "http://localhost:5000/api";

  useEffect(() => {
    let mounted = true;
    axios.get(`${API_BASE}/categories`).then(res => {
      if (mounted && res.data && Array.isArray(res.data)) setCategories(res.data);
    }).catch(()=>{ if(mounted) setCategories([]); });
    return ()=> mounted = false;
  }, [API_BASE]);

  return (
    <nav style={{ background: "#2f855a", color: "#fff", padding: "8px 10%" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 24 }}>
        <button onClick={() => setOpen(o => !o)} style={{ background: "#fff", color: "#2f855a", padding: "6px 10px", borderRadius: 6 }}>
          ☰ DANH MỤC SẢN PHẨM ({categories.length})
        </button>
        <div style={{ display: "flex", gap: 16 }}>
          <Link to="/">Trang chủ</Link>
          <Link to="/product">Sản phẩm</Link>
        </div>
      </div>

      {open && (
        <div style={{ marginTop: 8, background: "#fff", color: "#333", borderRadius: 8, padding: 10 }}>
          {categories.length === 0 ? <div>Không có danh mục</div> :
            <ul style={{ listStyle: "none", padding: 0, margin: 0 }}>
              {categories.map(c => <li key={c._id}><Link to={`/category/${c.slug}`}>{c.name}</Link></li>)}
            </ul>}
        </div>
      )}
    </nav>
  );
};

export default Navbar;
